from flask import Flask, request, jsonify, session, redirect, url_for
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import smtplib
import os
from datetime import datetime, timedelta
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
import logging

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///mfa_system.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db = SQLAlchemy(app)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# User model
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(255), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(255), nullable=True)
    reset_token = db.Column(db.String(255), nullable=True)
    reset_token_expires = db.Column(db.DateTime, nullable=True)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

# Validate email format
def is_valid_email(email):
    if not email or '@' not in email:
        return False
    try:
        local, domain = email.rsplit('@', 1)
        if not local or not domain:
            return False
        return True
    except ValueError:
        return False

# Send email function
def send_reset_email(email, reset_link):
    try:
        # In production, use proper email configuration
        msg = MIMEMultipart()
        msg['From'] = os.environ.get('EMAIL_USER', 'noreply@yourapp.com')
        msg['To'] = email
        msg['Subject'] = "MFA Reset Request"
        
        body = f"""
        Hello,
        
        You have requested to reset your MFA settings. Click the link below to disable MFA and regain access:
        
        {reset_link}
        
        If you did not request this, please ignore this email.
        
        Best regards,
        Your App Team
        """
        
        msg.attach(MIMEText(body, 'plain'))
        
        # For demo purposes - in production use proper SMTP
        logger.info(f"Reset email sent to {email}")
        return True
    except Exception as e:
        logger.error(f"Failed to send email: {e}")
        return False

# Generate secure token
def generate_secure_token():
    return secrets.token_urlsafe(32)

# Validate reset token
def is_valid_reset_token(user):
    if not user.reset_token or not user.reset_token_expires:
        return False
    return datetime.utcnow() < user.reset_token_expires

# Enable MFA
@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401
    
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    data = request.get_json()
    if not data or 'mfa_secret' not in data:
        return jsonify({'error': 'Missing MFA secret'}), 400
    
    user.mfa_secret = data['mfa_secret']
    user.mfa_enabled = True
    db.session.commit()
    
    return jsonify({'message': 'MFA enabled successfully'}), 200

# Disable MFA
@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401
    
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    user.mfa_enabled = False
    user.mfa_secret = None
    db.session.commit()
    
    return jsonify({'message': 'MFA disabled successfully'}), 200

# Reset MFA endpoint
@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    email = data.get('email', '').strip().lower()
    
    if not is_valid_email(email):
        return jsonify({'error': 'Invalid email format'}), 400
    
    user = User.query.filter_by(email=email).first()
    if not user:
        # Return success even for non-existent users to prevent enumeration
        return jsonify({'message': 'If account exists, reset instructions sent'}), 200
    
    # Generate reset token
    reset_token = generate_secure_token()
    reset_expires = datetime.utcnow() + timedelta(hours=24)
    
    user.reset_token = reset_token
    user.reset_token_expires = reset_expires
    db.session.commit()
    
    # Generate reset link
    reset_link = f"{request.host_url}reset-mfa/{reset_token}"
    
    # Send email
    if send_reset_email(email, reset_link):
        logger.info(f"Reset email sent to {email}")
    else:
        logger.error(f"Failed to send reset email to {email}")
    
    return jsonify({'message': 'If account exists, reset instructions sent'}), 200

# Handle reset token
@app.route('/reset-mfa/<token>', methods=['GET'])
def handle_reset_token(token):
    if not token:
        return jsonify({'error': 'Invalid token'}), 400
    
    user = User.query.filter_by(reset_token=token).first()
    if not user or not is_valid_reset_token(user):
        return jsonify({'error': 'Invalid or expired token'}), 400
    
    # Disable MFA
    user.mfa_enabled = False
    user.mfa_secret = None
    user.reset_token = None
    user.reset_token_expires = None
    db.session.commit()
    
    logger.info(f"MFA reset for user {user.id}")
    
    return jsonify({'message': 'MFA has been reset. You can now log in with just your password.'}), 200

# Login endpoint (simplified for demo)
@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    email = data.get('email', '').strip().lower()
    password = data.get('password', '')
    
    if not is_valid_email(email) or not password:
        return jsonify({'error': 'Invalid credentials'}), 400
    
    user = User.query.filter_by(email=email).first()
    if not user or not check_password_hash(user.password_hash, password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Set session
    session['user_id'] = user.id
    session['email'] = user.email
    
    # Check if MFA is enabled
    if user.mfa_enabled:
        return jsonify({'message': 'MFA required', 'mfa_required': True}), 200
    else:
        return jsonify({'message': 'Login successful', 'mfa_required': False}), 200

